import React, { useState, useEffect } from 'react';
import { useInterview } from '../context/InterviewContext';
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Box,
  CircularProgress,
  Alert
} from '@mui/material';

function Interview() {
  const {
    currentQuestion,
    feedback,
    nextQuestion,
    loading,
    error,
    startInterview,
    submitResponse
  } = useInterview();

  const [response, setResponse] = useState('');

  useEffect(() => {
    startInterview();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    await submitResponse(response);
    setResponse('');
  };

  return (
    <Container maxWidth="md" sx={{ mt: 4 }}>
      <Paper elevation={3} sx={{ p: 4 }}>
        <Typography variant="h4" gutterBottom>
          AI Interview
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {loading ? (
          <Box display="flex" justifyContent="center" my={4}>
            <CircularProgress />
          </Box>
        ) : (
          <>
            <Typography variant="h6" gutterBottom>
              Current Question:
            </Typography>
            <Typography paragraph>{currentQuestion}</Typography>

            <form onSubmit={handleSubmit}>
              <TextField
                fullWidth
                multiline
                rows={4}
                variant="outlined"
                label="Your Response"
                value={response}
                onChange={(e) => setResponse(e.target.value)}
                sx={{ mb: 2 }}
              />
              <Button
                type="submit"
                variant="contained"
                color="primary"
                disabled={!response.trim()}
              >
                Submit Response
              </Button>
            </form>

            {feedback && (
              <Box mt={4}>
                <Typography variant="h6" gutterBottom>
                  Feedback:
                </Typography>
                <Typography paragraph>{feedback}</Typography>
              </Box>
            )}

            {nextQuestion && (
              <Box mt={4}>
                <Typography variant="h6" gutterBottom>
                  Next Question:
                </Typography>
                <Typography paragraph>{nextQuestion}</Typography>
              </Box>
            )}
          </>
        )}
      </Paper>
    </Container>
  );
}

export default Interview;
